& {
Set-StrictMode -Version Latest
$ErrorActionPreference = "Stop"
$Repo = xyz_repo_or_path
$AgentSpec = xyz_gnhf_agent_spec
$AgentCommand = xyz_agent_command
$AgentProbeArgs = @(xyz_agent_probe_args)
$TimeoutSeconds = 20

if (-not (Test-Path -LiteralPath "$Repo\.git")) {
throw "Git repository not found: $Repo"
}

$Dirty = @(git -C $Repo status --porcelain)
if ($Dirty.Count -gt 0) {
$Dirty
throw "Repository must be clean before an unattended run."
}

$Gnhf = Get-Command gnhf -ErrorAction SilentlyContinue
if (-not $Gnhf) { throw "gnhf is not available on PATH." }

$Resolved = Get-Command $AgentCommand -ErrorAction SilentlyContinue
if (-not $Resolved) { throw "Agent command not found: $AgentCommand" }

if ($AgentSpec -notmatch "^acp:" -and $Resolved.Source -match "\.(cmd|bat)$") {
throw "Native GNHF agent resolves to a CMD/BAT shim. Prove an agentPathOverride or use a proven ACP/native executable before running overnight."
}

$Psi = [Diagnostics.ProcessStartInfo]::new()
$Psi.FileName = $Resolved.Source
$Psi.UseShellExecute = $false
$Psi.RedirectStandardOutput = $true
$Psi.RedirectStandardError = $true
$Psi.CreateNoWindow = $true
foreach ($Arg in $AgentProbeArgs) { [void]$Psi.ArgumentList.Add($Arg) }

$Process = [Diagnostics.Process]::new()
$Process.StartInfo = $Psi
[void]$Process.Start()
if (-not $Process.WaitForExit($TimeoutSeconds * 1000)) {
try { $Process.Kill($true) } catch {}
throw "Agent probe timed out after $TimeoutSeconds seconds."
}

$Stdout = $Process.StandardOutput.ReadToEnd().Trim()
$Stderr = $Process.StandardError.ReadToEnd().Trim()
if ($Process.ExitCode -ne 0) {
throw "Agent spawn probe failed with exit code $($Process.ExitCode): $Stderr"
}

[pscustomobject]@{
Repo = (Resolve-Path $Repo).Path
AgentSpec = $AgentSpec
AgentCommand = $AgentCommand
ResolvedPath = $Resolved.Source
ExitCode = $Process.ExitCode
Output = $Stdout
ReadyForP38 = $true
} | Format-List
}
